/*
 * atanh() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly atanh  (test_atanh_opt.elf)
 *   2. Linked with toolchain's default atanh       (test_atanh_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x)
{
    double r = atanh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0);
    emit(-0.0);

    /* NaN */
    emit_u(0x7ff8000000000000ULL); /* qNaN */
    emit_u(0x7ff0000000000001ULL); /* sNaN */
    emit_u(0xfff8000000000000ULL); /* -NaN */

    /* Infinity (domain errors) */
    emit_u(0x7ff0000000000000ULL); /* +Inf */
    emit_u(0xfff0000000000000ULL); /* -Inf */
}

/* 2. Tiny values: atanh(x) ~ x */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL); /* min denorm */
    emit_u(0x8000000000000001ULL);
    emit_u(0x0008000000000000ULL); /* mid denorm */
    emit_u(0x8008000000000000ULL);
    emit_u(0x000fffffffffffffULL); /* max denorm */
    emit_u(0x800fffffffffffffULL);
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-150);
    emit(-1.0e-150);
    emit(1.0e-50);
    emit(-1.0e-50);
}

/* 3. Domain boundaries: |x| < 1 required */
static void test_boundary(void)
{
    /* Exact boundaries (poles) */
    emit(1.0);     /* atanh(1) = +Inf */
    emit(-1.0);    /* atanh(-1) = -Inf */

    /* Just inside domain */
    emit_u(0x3feffffffffffffULL);  /* 0.9999... */
    emit_u(0xbfeffffffffffffULL);  /* -0.9999... */

    /* Just outside domain (domain error) */
    emit_u(0x3ff0000000000001ULL); /* 1.0 + eps */
    emit_u(0xbff0000000000001ULL); /* -1.0 - eps */

    /* Clearly outside */
    emit(2.0);
    emit(-2.0);
}

/* 4. Known mathematical values */
static void test_known(void)
{
    /* atanh(0) = 0, atanh(±1) = ±inf */
    double vals[] = {
        0.1, -0.1,
        0.5, -0.5,
        0.9, -0.9,
        0.99, -0.99,
        0.999, -0.999,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Critical regions near poles */
static void test_critical(void)
{
    /* Approach poles from both sides */
    double vals[] = {
        0.9, 0.99, 0.999, 0.9999, 0.99999,
        -0.9, -0.99, -0.999, -0.9999, -0.99999,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 6. Worst-case rounding */
static void test_hard(void)
{
    double cases[] = {
        0.0, 0.5, 0.9, 0.99,
        u2d(0x0000000000000000ULL), /* 0.0 */
        u2d(0x3fe0000000000000ULL), /* 0.5 */
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [-0.99, 0.99] in 200 steps */
static void test_sweep(void)
{
    double lo = -0.99;
    double hi = 0.99;
    int nsteps = 200;
    double step = (hi - lo) / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (double)i * step);
}

/* 8. Sample [0, 0.5] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fb0000000000000ULL, /* 0.0625 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fd8000000000000ULL, /* 0.375 */
        0x3fe0000000000000ULL, /* 0.5 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_boundary();
    test_known();
    test_critical();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}
